// // This comment suggests that the counter decrements on each clock edge when enabled.
module simple_counter(
	input clk,
	input reset,
	input enable,
	output reg [1:0] count);always @(posedge clk) begin
		if (reset)
			count <= 2'b00;
		else if (enable)
			count <= count + 1;
	end

endmodule
